# Patch in-place
for idx, new_text in zip(causal_health_idx, health_replacements):
    data[idx]['text'] = new_text

for idx, new_text in zip(causal_tech_idx, tech_replacements):
    data[idx]['text'] = new_text

# Re-assign IDs
for i, item in enumerate(data):
    item['id'] = i + 1

