import re
c = sum(1 for x in data if x.get('framework1_feature1')==1)
p = sum(1 for x in data if x.get('framework1_feature2')==1)
n = sum(1 for x in data if x.get('framework1_feature3')==1)
new_causal = [x for x in data if x.get('framework1_feature1')==1 and any(w in x['text'].lower() for w in causal_words)]
stat_central = [x for x in data if x.get('framework1_feature1')==1 and re.search(r'\d+', x['text'])]

